function init() {
    scene = new THREE.Scene();
    scene.background = new THREE.Color(0x1a1a1a);

    camera = new THREE.PerspectiveCamera(75, window.innerWidth / window.innerHeight, 0.1, 1000);
    camera.position.set(0, 1, -3);
    camera.lookAt(0, 0, 0);

    renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(window.innerWidth, window.innerHeight);
    renderer.setPixelRatio(window.devicePixelRatio);
    document.getElementById('canvas-container').appendChild(renderer.domElement);

    controls = new THREE.OrbitControls(camera, renderer.domElement);
    controls.enableDamping = true;
    controls.dampingFactor = 0.05;

    const gridHelper = new THREE.GridHelper(10, 10, 0x444444, 0x333333);
    scene.add(gridHelper);

    const axesHelper = new THREE.AxesHelper(2);
    scene.add(axesHelper);

    const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
    scene.add(ambientLight);

    const directionalLight = new THREE.DirectionalLight(0xffffff, 0.8);
    directionalLight.position.set(5, 10, 7);
    scene.add(directionalLight);

    window.addEventListener('resize', onWindowResize);

    loadJSONData();
}

async function loadJSONData() {
    try {
        const response = await fetch('学生视频.json');
        keypointsData = await response.json();
        document.getElementById('frame-info').textContent = `帧: 0 / ${keypointsData.length}`;
        document.getElementById('status').textContent = '状态: 数据已加载';

        if (keypointsData.length > 0) {
            renderFrame(0);
        }
    } catch (error) {
        console.error('加载JSON数据失败:', error);
        document.getElementById('status').textContent = '状态: 加载失败';
    }
}

function createKeypointMesh(index) {
    const geometry = new THREE.SphereGeometry(0.03, 16, 16);
    const material = new THREE.MeshPhongMaterial({
        color: 0x00ff00,
        shininess: 100
    });
    const sphere = new THREE.Mesh(geometry, material);
    sphere.userData = { index: index };
    return sphere;
}

function createLabelSprite(text) {
    const canvas = document.createElement('canvas');
    const context = canvas.getContext('2d');
    canvas.width = 64;
    canvas.height = 64;

    context.fillStyle = 'rgba(0, 0, 0, 0.5)';
    context.fillRect(0, 0, canvas.width, canvas.height);

    context.font = 'bold 32px Arial';
    context.fillStyle = 'white';
    context.textAlign = 'center';
    context.textBaseline = 'middle';
    context.fillText(text, canvas.width / 2, canvas.height / 2);

    const texture = new THREE.CanvasTexture(canvas);
    const material = new THREE.SpriteMaterial({
        map: texture,
        transparent: true
    });
    const sprite = new THREE.Sprite(material);
    sprite.scale.set(0.1, 0.1, 1);
    return sprite;
}

function createThickBone(startPoint, endPoint, color) {
    const direction = new THREE.Vector3(
        endPoint[0] - startPoint[0],
        endPoint[2] - startPoint[2],
        endPoint[1] - startPoint[1]
    );
    const length = direction.length();

    const geometry = new THREE.CylinderGeometry(0.02, 0.02, length, 8);
    const material = new THREE.MeshPhongMaterial({
        color: color,
        shininess: 100
    });
    const cylinder = new THREE.Mesh(geometry, material);

    const midpoint = new THREE.Vector3(
        (startPoint[0] + endPoint[0]) / 2,
        (startPoint[2] + endPoint[2]) / 2,
        (startPoint[1] + endPoint[1]) / 2
    );
    cylinder.position.copy(midpoint);

    cylinder.quaternion.setFromUnitVectors(
        new THREE.Vector3(0, 1, 0),
        direction.normalize()
    );

    return cylinder;
}

function renderFrame(frameIndex) {
    if (frameIndex < 0 || frameIndex >= keypointsData.length) return;

    const frame = keypointsData[frameIndex];
    const keypoints = frame.instances[0].keypoints;

    clearScene();

    keypoints.forEach((keypoint, index) => {
        const mesh = createKeypointMesh(index);
        mesh.position.set(keypoint[0], keypoint[2], keypoint[1]);
        scene.add(mesh);
        keypointsMeshes.push(mesh);

        const label = createLabelSprite(index.toString());
        label.position.set(keypoint[0], keypoint[2] + 0.08, keypoint[1]);
        scene.add(label);
        labelSprites.push(label);
    });

    boneConnections.forEach(connection => {
        const startIdx = connection.points[0];
        const endIdx = connection.points[1];
        const color = connection.color;

        if (startIdx < keypoints.length && endIdx < keypoints.length) {
            const startPoint = keypoints[startIdx];
            const endPoint = keypoints[endIdx];
            const thickBone = createThickBone(startPoint, endPoint, color);
            scene.add(thickBone);
            bonesLines.push(thickBone);
        }
    });

    document.getElementById('frame-info').textContent = `帧: ${frameIndex + 1} / ${keypointsData.length}`;
}

function clearScene() {
    keypointsMeshes.forEach(mesh => {
        scene.remove(mesh);
        mesh.geometry.dispose();
        mesh.material.dispose();
    });
    keypointsMeshes = [];

    bonesLines.forEach(bone => {
        scene.remove(bone);
        bone.geometry.dispose();
        bone.material.dispose();
    });
    bonesLines = [];

    labelSprites.forEach(sprite => {
        scene.remove(sprite);
        sprite.material.map.dispose();
        sprite.material.dispose();
    });
    labelSprites = [];
}

let isPlaying = false;
let currentFrame = 0;
let lastTime = 0;
const frameInterval = 33;

function playAnimation() {
    if (isPlaying) return;
    isPlaying = true;
    document.getElementById('playBtn').disabled = true;
    document.getElementById('pauseBtn').disabled = false;
    document.getElementById('status').textContent = '状态: 播放中';
    animate();
}

function pauseAnimation() {
    isPlaying = false;
    document.getElementById('playBtn').disabled = false;
    document.getElementById('pauseBtn').disabled = true;
    document.getElementById('status').textContent = '状态: 已暂停';
    if (animationId) cancelAnimationFrame(animationId);
}

function resetAnimation() {
    pauseAnimation();
    currentFrame = 0;
    renderFrame(0);
    document.getElementById('status').textContent = '状态: 已重置';
}

function animate(time) {
    if (!isPlaying) return;
    if (!lastTime) lastTime = time;
    const deltaTime = time - lastTime;
    if (deltaTime >= frameInterval) {
        currentFrame++;
        if (currentFrame >= keypointsData.length) currentFrame = 0;
        renderFrame(currentFrame);
        lastTime = time;
    }
    controls.update();
    renderer.render(scene, camera);
    animationId = requestAnimationFrame(animate);
}

